#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int n,t,ans;
int a[1000005];
int qp(int a,int b)
{
	int r=1;
	wh(b)
	{
		if(b&1)r=r*a;
		a=a*a;
		b>>=1;
	}
	return r;
}
signed main(void)
{
	IOS
	cin.tie(0);
	cin>>n>>t;
	FOR(i,1,n)
	{
		cin>>a[i];
	}
	int ed=t-1;
	FOR(i,1,n-1)
	{
		int s=max(a[i],a[i+1]);
		if(s>ed)continue;
		ans+=ed-s+1;
	}
	cout<<ans;
	return 0;
}
